sys_script_include.script:
var WRMReservationHelper = Class.create();
WRMReservationHelper.prototype = {
    initialize: function() {},

    checkIn: function(sysId, userId) {
    gs.info('WRMHelper checkIn called - sysId: ' + sysId + ' userId: ' + userId, 'WRMHelper');
    var gr = new GlideRecord('x_451445_wrm_reservation_tracker');
    gr.addQuery('sys_id', sysId);
    gr.addQuery('reserved_for', userId);
    gr.query();
    gs.info('WRMHelper hasNext: ' + gr.hasNext(), 'WRMHelper');
    if (!gr.next()) return {success: false, error: 'Record not found or unauthorized.'};
    gs.info('WRMHelper status: ' + gr.getValue('reservation_status'), 'WRMHelper');
    if (gr.getValue('reservation_status') !== 'pending_check_in') return {success: false, error: 'Status is no longer Pending check-in.'};
    gr.setValue('reservation_status', 'checked_in');
    gr.setValue('work_notes', 'Reservation checked in by ' + gs.getUserDisplayName());
    gr.setWorkflow(true);
    gr.autoSysFields(true);
    var result = gr.update();
    gs.info('WRMHelper update result: ' + result, 'WRMHelper');
    return result ? {success: true, message: 'Checked in successfully.'} : {success: false, error: 'Update failed.'};
},

    checkOut: function(sysId, userId) {
        var gr = new GlideRecord('x_451445_wrm_reservation_tracker');
        gr.addQuery('sys_id', sysId);
        gr.addQuery('reserved_for', userId);
        gr.query();
        if (!gr.next()) return {success: false, error: 'Record not found or unauthorized.'};
        if (gr.getValue('reservation_status') !== 'checked_in') return {success: false, error: 'Status is no longer Checked-in.'};
        gr.setValue('reservation_status', 'checked_out');
        gr.setValue('work_notes', 'Reservation Checked-out by ' + gs.getUserDisplayName());
        gr.setWorkflow(true);
        gr.autoSysFields(true);
        var result = gr.update();
        return result ? {success: true, message: 'Checked out successfully.'} : {success: false, error: 'Update failed.'};
    },

    type: 'WRMReservationHelper'
};
